import{_ as t,o,c as r,a2 as e}from"./chunks/framework.Do_4EYrn.js";const s="/assets/001_image_IZzfbK38Ao.D0N9ZTVW.png",i="/assets/002_image_WF3ab0WSbo.DphxGEGY.png",l="/assets/003_image_ZssEbuMsdo.Dhg8VjKq.png",n="/assets/004_image_KVIJbpUZdo.BRYRrqpV.png",p="/assets/005_image_FPy1bGJJZo.CH9_F62R.png",d="/assets/006_image_WQ6Zb1Rero.JBzT8KRW.png",g="/assets/007_image_M2itbQUceo.DA3g1zrW.png",A=JSON.parse('{"title":"第 7 章 WorkBuddy 使用连接器","description":"::: warning 安居建业内部使用提示 仅连接公司批准的系统、账号与数据源。首次接入应从只读、最小权限和测试目录开始；访问令牌、密码和连接串不得写入提示词、截图或共享文档。涉及业务系统写入、外部发送或批量处理时，必须先确认授权范围并保留操作记录。 :::","frontmatter":{},"headers":[],"relativePath":"bluebook/第一篇 使用手册：先把 WorkBuddy 用起来/第 7 章 WorkBuddy 使用连接器/index.md","filePath":"bluebook/第一篇 使用手册：先把 WorkBuddy 用起来/第 7 章 WorkBuddy 使用连接器/index.md","lastUpdated":1784290813000}'),c={name:"bluebook/第一篇 使用手册：先把 WorkBuddy 用起来/第 7 章 WorkBuddy 使用连接器/index.md"};function _(u,a,m,P,h,C){return o(),r("div",null,[...a[0]||(a[0]=[e('<h1 id="第-7-章-workbuddy-使用连接器" tabindex="-1">第 7 章 WorkBuddy 使用连接器 <a class="header-anchor" href="#第-7-章-workbuddy-使用连接器" aria-label="Permalink to &quot;第 7 章 WorkBuddy 使用连接器&quot;">​</a></h1><div class="warning custom-block"><p class="custom-block-title">安居建业内部使用提示</p><p>仅连接公司批准的系统、账号与数据源。首次接入应从只读、最小权限和测试目录开始；访问令牌、密码和连接串不得写入提示词、截图或共享文档。涉及业务系统写入、外部发送或批量处理时，必须先确认授权范围并保留操作记录。</p></div><p><strong>MCP</strong>指的是 **Model Context Protocol（模型上下文协议），**是由 Anthropic 于 2024 年底推出并开源的一个开放标准协议，目前已经成为 AI 领域最热门的基础设施之一。</p><p>用一个通俗的比喻：<strong>MCP 就是 AI 世界的“USB-C 接口”。</strong></p><h2 id="为什么需要-mcp" tabindex="-1">为什么需要 MCP？ <a class="header-anchor" href="#为什么需要-mcp" aria-label="Permalink to &quot;为什么需要 MCP？&quot;">​</a></h2><p>在过去，如果你想让一个 AI 助手（Agent）连接外部工具（比如 GitHub、本地文件系统、PostgreSQL 数据库、Slack 等），开发者必须为“每一个 AI 应用”和“每一个工具”编写专门的对接代码。如果有 10 个 AI 应用和 10 个工具，就需要写 100 个接口（N × M 的集成噩梦）。</p><p>有了 MCP，工具开发者只需要按照 MCP 标准开发一个“MCP Server”（相当于 USB-C 设备），而任何支持 MCP 的 AI 应用（如 Cursor、各类 Agent 框架）只需内置“MCP Client”（相当于 USB-C 接口），就能<strong>即插即用</strong>。这就把 N × M 的复杂开发工作，简化成了 N + M。</p><h2 id="mcp-的核心特点" tabindex="-1">MCP 的核心特点 <a class="header-anchor" href="#mcp-的核心特点" aria-label="Permalink to &quot;MCP 的核心特点&quot;">​</a></h2><ul><li>统一的标准化协议（告别重复造轮子）</li></ul><p>MCP 提供了一套通用的规范（基于 JSON-RPC）。无论是读取本地文件、查询数据库，还是调用第三方 SaaS API，AI 都能通过同一套协议逻辑去理解和调用。这大幅降低了 Agent 开发中工具集成的门槛，让开发者可以把精力集中在 Agent 的核心逻辑上，而不是写繁琐的 API 对接代码。</p><ul><li>支持三大核心能力</li></ul><p>MCP 不仅能让 AI “做事”，还能让 AI “看数据”和“按套路出牌”，它标准化了三种核心原语：</p><ul><li><p><strong>Tools（工具）</strong>：允许 AI 执行操作。例如：运行一段代码、在 Jira 创建一个任务、向数据库写入数据。</p></li><li><p><strong>Resources（资源/上下文）</strong>：允许 AI 读取外部数据。例如：获取 Git 仓库的文件列表、查询向量数据库中的特定片段，作为回答问题的上下文。</p></li><li><p><strong>Prompts（提示词模板）</strong>：提供预定义的交互模板，让用户或 AI 能以标准化的方式触发特定的复杂工作流。</p></li><li><p>C/S 架构与高度解耦，MCP 采用客户端-服务端（Client-Server）架构：</p><ul><li><strong>MCP Host</strong>：你使用的 AI 宿主应用（如 IDE、Agent 平台）。</li><li><strong>MCP Client</strong>：Host 内部负责与 Server 保持 1:1 连接的组件。</li><li><strong>MCP Server</strong>：轻量级的独立程序，专门负责暴露特定工具或数据的能力。</li></ul></li></ul><p>这种解耦意味着你可以随时替换底层的大模型，或者随时增加新的数据源，而无需重构整个 Agent 系统。</p><ul><li>本地优先与安全性（隐私友好）</li></ul><p>MCP 支持通过本地标准输入输出（stdio）或本地 HTTP 进行通信。这意味着你的 MCP Server 可以完全运行在本地电脑上。敏感数据（如本地代码、私有数据库内容、受控业务数据）不需要上传到云端第三方服务器，AI 模型只在需要推理时获取必要的上下文，极大提升了企业级应用的数据安全性。</p><h2 id="加载一个连接器" tabindex="-1">加载一个连接器 <a class="header-anchor" href="#加载一个连接器" aria-label="Permalink to &quot;加载一个连接器&quot;">​</a></h2><p><strong>当前已支持 QQ 邮箱、腾讯文档、腾讯乐享、腾讯会议、TAPD 等连接器。</strong></p><p><img src="'+s+'" alt="" loading="lazy"></p><p>比如加载腾讯会议连接器，</p><p><img src="'+i+'" alt="" loading="lazy"></p><p><img src="'+l+'" alt="" loading="lazy"></p><h2 id="创建一个任务" tabindex="-1">创建一个任务 <a class="header-anchor" href="#创建一个任务" aria-label="Permalink to &quot;创建一个任务&quot;">​</a></h2><p>帮我创建一个明天下午 3 点的会议，</p><p><img src="'+n+'" alt="" loading="lazy"></p><p>主题“项目讨论”，时长1h</p><p><img src="'+p+'" alt="" loading="lazy"></p><p>创建成功</p><p><img src="'+d+'" alt="" loading="lazy"></p><h2 id="新建连接器" tabindex="-1">新建连接器 <a class="header-anchor" href="#新建连接器" aria-label="Permalink to &quot;新建连接器&quot;">​</a></h2><p>连接器管理页右上角点“自定义连接器”，按引导配置 MCP（含服务地址、鉴权方式），并提示自定义连接器的访问范围由用户配置</p><p><img src="'+g+'" alt="" loading="lazy"></p>',32)])])}const M=t(c,[["render",_]]);export{A as __pageData,M as default};
